var bootstrapFolderQueries = map[string]struct {
	labelIDs []string
	query    string
}{
	"inbox":     {labelIDs: []string{"INBOX"}},
	"sent":      {labelIDs: []string{"SENT"}},
	"starred":   {labelIDs: []string{"STARRED"}},
	"important": {labelIDs: []string{"IMPORTANT"}},
	"spam":      {labelIDs: []string{"SPAM"}},
	"trash":     {labelIDs: []string{"TRASH"}},
	"archived":  {query: "in:anywhere -label:inbox -label:sent -label:spam -label:trash"},
	"done":      {query: "in:anywhere -label:inbox"},
}

func newBootstrapCmd(flags *rootFlags) *cobra.Command {
	var foldersCSV string
	var perFolder int
	var full bool
	var dbPath string

	cmd := &cobra.Command{
		Use:   "bootstrap",
		Short: "Bootstrap recent Gmail messages into local SQLite",
		Long: `Bootstrap pulls the latest messages from selected Gmail folders into
the local SQLite store. Later read commands can use the local messages table
without paying a network round trip for every query.`,
		Example: `  superhuman-pp-cli bootstrap
  superhuman-pp-cli bootstrap --folders inbox,sent --per-folder 25
  superhuman-pp-cli bootstrap --full`,
		Annotations: map[string]string{
			"pp:endpoint":   "bootstrap",
			"mcp:read-only": "false",
		},
		RunE: func(cmd *cobra.Command, args []string) error {
			if perFolder <= 0 {
				return usageErr(fmt.Errorf("bootstrap: --per-folder must be greater than 0"))
			}
			folders, err := parseBootstrapFolders(foldersCSV)
			if err != nil {
				return usageErr(err)
			}
			return runBootstrap(cmd, flags, bootstrapOptions{
				Folders:   folders,
				PerFolder: perFolder,
				Full:      full,
				DBPath:    dbPath,
			})
		},
	}
	cmd.Flags().StringVar(&foldersCSV, "folders", "inbox,sent,archived", "Comma-separated Gmail folders to bootstrap")
	cmd.Flags().IntVar(&perFolder, "per-folder", 100, "Maximum messages to fetch per folder")
	cmd.Flags().BoolVar(&full, "full", false, "Discard existing local messages for the account before bootstrapping")
	cmd.Flags().StringVar(&dbPath, "db", "", "SQLite database path (default: platform config path)")
	return cmd
}

type bootstrapOptions struct {
	Folders   []string
	PerFolder int
	Full      bool
	DBPath    string
}

type bootstrapSummary struct {
	Event    string         `json:"event"`
	Account  string         `json:"account"`
	Fetched  int            `json:"fetched"`
	Folders  map[string]int `json:"folders"`
	Full     bool           `json:"full"`
	DBPath   string         `json:"db_path"`
	Duration int64          `json:"duration_ms"`
}

func parseBootstrapFolders(input string) ([]string, error) {
	seen := map[string]bool{}
	var folders []string
	for _, raw := range strings.Split(input, ",") {
		folder := strings.ToLower(strings.TrimSpace(raw))
		if folder == "" {
			continue
		}
		if _, ok := bootstrapFolderQueries[folder]; !ok {
			return nil, fmt.Errorf("bootstrap: unsupported --folders value %q (valid: %s)", folder, strings.Join(validBootstrapFolders(), ", "))
		}
		if !seen[folder] {
			seen[folder] = true
			folders = append(folders, folder)
		}
	}
	if len(folders) == 0 {
		return nil, fmt.Errorf("bootstrap: --folders must name at least one folder (valid: %s)", strings.Join(validBootstrapFolders(), ", "))
	}
	return folders, nil
}

func validBootstrapFolders() []string {
	valid := make([]string, 0, len(bootstrapFolderQueries))
	for folder := range bootstrapFolderQueries {
		valid = append(valid, folder)
	}
	sort.Strings(valid)
	return valid
}

func runBootstrap(cmd *cobra.Command, flags *rootFlags, opts bootstrapOptions) error {
	if cliutil.IsVerifyEnv() {
		fmt.Fprintln(cmd.OutOrStdout(), "would bootstrap Gmail messages into local SQLite")
		return nil
	}
	acct, err := resolveActiveAccount(flags)
	if err != nil {
		return authErr(fmt.Errorf("bootstrap: %w", err))
	}
	gc := gmail.New(acct.Store, acct.Email, acct.GoogleID, acct.AccessToken)
	gc.Stderr = cmd.ErrOrStderr()

	dbPath := opts.DBPath
	if dbPath == "" {
		dbPath = defaultDBPath("superhuman-pp-cli")
	}
	db, err := store.OpenWithContext(cmd.Context(), dbPath)
	if err != nil {
		return fmt.Errorf("opening local database: %w", err)
	}
	defer db.Close()

	if opts.Full {
		if err := db.ClearMessagesForAccount(cmd.Context(), acct.Email); err != nil {
			return fmt.Errorf("bootstrap --full: %w", err)
		}
	}

	started := time.Now()
	summary := bootstrapSummary{
		Event:   "bootstrap_summary",
		Account: acct.Email,
		Folders: map[string]int{},
		Full:    opts.Full,
		DBPath:  dbPath,
	}
	var latestHistory string
	for _, folder := range opts.Folders {
		count, historyID, err := bootstrapFolder(cmd.Context(), cmd, flags, gc, db, acct.Email, folder, opts.PerFolder)
		// PATCH(greptile-bootstrap-history-checkpoint): roll up the MAX
		// historyID across all folders, not the last-folder's. Sequential
		// assignment would have set latestHistory to whichever folder ran
		// last, which is rarely the folder with the highest historyID.
		latestHistory = maxHistoryID(latestHistory, historyID)
		if saveErr := db.SaveHistoryState(cmd.Context(), acct.Email, latestHistory, time.Now(), started); saveErr != nil && err == nil {
			err = saveErr
		}
		summary.Folders[folder] = count
		summary.Fetched += count
		if err != nil {
			if gmail.IsAuth(err) {
				return authErr(fmt.Errorf("bootstrap: %w", err))
			}
			return apiErr(fmt.Errorf("bootstrap %s: %w", folder, err))
		}
	}
	summary.Duration = time.Since(started).Milliseconds()
	if flags.asJSON || (!isTerminal(cmd.OutOrStdout()) && !flags.csv && !flags.quiet && !flags.plain) {
		if flags.quiet {
			return nil
		}
		return flags.printJSON(cmd, summary)
	}
	fmt.Fprintf(cmd.OutOrStdout(), "Bootstrapped %d messages for %s into %s\n", summary.Fetched, acct.Email, dbPath)
	return nil
}

func bootstrapFolder(ctx context.Context, cmd *cobra.Command, flags *rootFlags, gc *gmail.Client, db *store.Store, accountEmail, folder string, perFolder int) (int, string, error) {
	spec := bootstrapFolderQueries[folder]
	pageToken := ""
	fetched := 0
	latestHistory := ""
	for fetched < perFolder {
		pageSize := perFolder - fetched
		if pageSize > 100 {
			pageSize = 100
		}
		refs, err := gc.ListMessages(ctx, spec.labelIDs, spec.query, pageSize, pageToken)
		if err != nil {
			return fetched, latestHistory, err
		}
		if len(refs.Messages) == 0 {
			break
		}
		batch := make([]store.StoredMessage, 0, len(refs.Messages))
		for _, ref := range refs.Messages {
			if err := ctx.Err(); err != nil {
				return fetched, latestHistory, err
			}
			msg, err := gc.GetMessage(ctx, ref.ID, "full")
			if err != nil {
				return fetched, latestHistory, err
			}
			batch = append(batch, storedMessageFromGmail(accountEmail, msg))
			// PATCH(greptile-bootstrap-history-checkpoint): take the MAXIMUM
			// historyID across all messages, not the LAST one written. Gmail
			// returns messages newest-first, so the last assignment landed on
			// the oldest historyID, and the subsequent watch/auto-refresh
			// would replay a wide history window before reaching the real
			// new state. maxHistoryID handles the stringified-uint64
			// comparison explicitly so callers don't accidentally compare
			// lexically (where "100" < "9").
			latestHistory = maxHistoryID(latestHistory, msg.HistoryID)
		}
		stored, err := db.UpsertGmailMessages(ctx, batch)
		if err != nil {
			return fetched, latestHistory, err
		}
		fetched += stored
		emitBootstrapProgress(cmd, flags, folder, fetched, minInt(perFolder, refs.ResultSizeEstimate))
		if refs.NextPageToken == "" || fetched >= perFolder {
			break
		}
		pageToken = refs.NextPageToken
	}
	return fetched, latestHistory, nil
}

func storedMessageFromGmail(accountEmail string, msg *gmail.Message) store.StoredMessage {
	headers := map[string]string{}
	for _, h := range msg.Headers {
		headers[strings.ToLower(h.Name)] = h.Value
	}
	raw, _ := json.Marshal(map[string]any{
		"id":           msg.ID,
		"threadId":     msg.ThreadID,
		"labelIds":     msg.LabelIDs,
		"snippet":      msg.Snippet,
		"historyId":    msg.HistoryID,
		"internalDate": msg.InternalDate,
		"headers":      msg.Headers,
		"body":         msg.Body,
		"htmlBody":     msg.HTMLBody,
		"attachments":  msg.Attachments,
	})
	return store.StoredMessage{
		ID:           msg.ID,
		ThreadID:     msg.ThreadID,
		AccountEmail: accountEmail,
		LabelIDs:     msg.LabelIDs,
		From:         headers["from"],
		To:           headers["to"],
		Cc:           headers["cc"],
		Subject:      headers["subject"],
		Snippet:      msg.Snippet,
		BodyPlain:    msg.Body,
		BodyHTML:     msg.HTMLBody,
		RFC822ID:     headers["message-id"],
		HistoryID:    msg.HistoryID,
		InternalDate: msg.InternalDate,
		Data:         raw,
	}
}

func emitBootstrapProgress(cmd *cobra.Command, flags *rootFlags, folder string, fetched, total int) {
	if !flags.agent || !flags.asJSON || flags.quiet {
		return
	}
	payload := map[string]any{
		"event":   "bootstrap_progress",
		"folder":  folder,
		"fetched": fetched,
		"total":   total,
	}
	data, err := json.Marshal(payload)
	if err != nil {
		return
	}
	fmt.Fprintln(cmd.OutOrStdout(), string(data))
}

func minInt(a, b int) int {
	if b <= 0 || a < b {
		return a
	}
	return b
}

// maxHistoryID returns the numerically greater of two Gmail historyId
// values. Gmail's historyId is a stringified uint64 (currently fits in 32
// bits but the API contract is the larger type), so a lexicographic
// comparison would put "9" above "100". big.Int.Cmp handles the full
// range with no overflow concern.
//
// Either argument may be empty: an empty string sorts below any populated
// value, which is what bootstrap callers want when accumulating a
// checkpoint from a freshly-zeroed local state.
func maxHistoryID(a, b string) string {
	if a == "" {
		return b
	}
	if b == "" {
		return a
	}
	ai, aok := new(big.Int).SetString(a, 10)
	bi, bok := new(big.Int).SetString(b, 10)
	if !aok || !bok {
		// Fall back to lex comparison if either side isn't a clean
		// decimal integer. This branch should be unreachable in
		// practice but keeps the function safe under unexpected input.
		if a >= b {
			return a
		}
		return b
	}
	if ai.Cmp(bi) >= 0 {
		return a
	}
	return b
}
